    <style>
      .chat-input {
        min-height: 44px;
        max-height: 200px;
      }

      .loading-indicator {
        display: inline-block;
        width: 20px;
        height: 20px;
        border: 3px solid #a0aec0;
        border-radius: 50%;
        border-top-color: #4299e1;
        animation: spin 1s ease-in-out infinite;
